1	'use client'
2	
3	import { useCallback } from 'react'
4	import { AgGridReact } from 'ag-grid-react'
5	import type { ColDef, RowClickedEvent, SelectionChangedEvent } from 'ag-grid-community'
6	
7	import 'ag-grid-community/styles/ag-grid.css'
8	import 'ag-grid-community/styles/ag-theme-alpine.css'
9	
10	interface DataTableProps<T> {
11	    columnDefs: ColDef<T>[]
12	    rowData: T[]
13	    onRowClick?: (row: T) => void
14	    onSelectionChange?: (rows: T[]) => void
15	    loading?: boolean
16	    height?: number
17	}
18	
19	const DEFAULT_COL_DEF: ColDef = {
20	    sortable: true,
21	    resizable: true,
22	}
23	
24	export function DataTable<T>({
25	    columnDefs,
26	    rowData,
27	    onRowClick,
28	    onSelectionChange,
29	    loading = false,
30	    height = 500,
31	}: DataTableProps<T>) {
32	    const onRowClickedHandler = useCallback(
33	        (event: RowClickedEvent<T>) => {
34	            if (onRowClick && event.data) {
35	                onRowClick(event.data)
36	            }
37	        },
38	        [onRowClick]
39	    )
40	
41	    const onSelectionChangedHandler = useCallback(
42	        (event: SelectionChangedEvent<T>) => {
43	            if (onSelectionChange) {
44	                const selected = event.api.getSelectedRows()
45	                onSelectionChange(selected)
46	            }
47	        },
48	        [onSelectionChange]
49	    )
50	
51	    return (
52	        <div className="ag-theme-alpine" style={{ height, width: '100%' }}>
53	            <AgGridReact<T>
54	                columnDefs={columnDefs}
55	                rowData={rowData}
56	                defaultColDef={DEFAULT_COL_DEF}
57	                rowSelection={{ mode: 'singleRow' }}
58	                pagination={true}
59	                paginationPageSize={20}
60	                loading={loading}
61	                overlayNoRowsTemplate="<span>데이터가 없습니다</span>"
62	                onRowClicked={onRowClickedHandler}
63	                onSelectionChanged={onSelectionChangedHandler}
64	            />
65	        </div>
66	    )
67	}
68
